SELECT id, user_id AS userId, category_id AS categoryId, type, amount, remark, record_date AS recordDate
FROM transaction_record
WHERE user_id = #{userId}

SELECT id, user_id AS userId, category_id AS categoryId, type, amount, remark, record_date AS recordDate
FROM transaction_record
WHERE user_id = #{userId} AND type = #{type}

SELECT id, user_id AS userId, category_id AS categoryId, type, amount, remark, record_date AS recordDate
FROM transaction_record
WHERE user_id = #{userId} AND record_date BETWEEN #{startRecordDate} AND #{endOfRecordDate}

SELECT  id, user_id AS userId, category_id AS categoryId, type, amount, remark, record_date AS recordDate
FROM transaction_record
WHERE user_id = #{userId}
ORDER BY record_date DESC, id DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) AS total
FROM transaction_record
WHERE user_id = #{userId}

